var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPERATOR_NPC_MINING_NULL","text":{"KOREA":"본 기는 현재 허가 없이 그라운드 원 상공을 침범하고 있다.","JPN":"本機は只今、許可なくグラウンド・ワン上空を侵犯している。","ENG":"This aircraft is currently violating the airspace above Ground One without authorization.","TWN":"你已未經許可侵入G1上空。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OPERATOR_NPC_MINING_NULL","text":{"KOREA":"목적을 밝히지 않으면 격추하겠다. 이건 마지막 경고다.","JPN":"目的を明らかにしなければ撃墜する。これは最後の警告だ。","ENG":"State your purpose or we will shoot you down. This is your final warning.","TWN":"若不表明來意，將立即擊落。這是最後警告。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"...공인카운터 힉스다.","JPN":"……公認カウンターのヒックスだ。","ENG":"...This is Official Counter Hicks.","TWN":"……我是認證制裁者，希克斯。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111010","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"격추하던지 말던지 맘대로 해.","JPN":"撃墜なり何なり好きにして。","ENG":"Shoot me down or don't. Do whatever you want.","TWN":"要不要擊落隨你們。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_111010","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"무슨 일이지?","JPN":"どうした？","ENG":"What's going on?","TWN":"發生什麼事了？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ADMIN_OMEN_OPR_NULL","text":{"KOREA":"챔버에서 도난 신고된 비행선이 관리본부로 접근 중입니다.","JPN":"チェンバーから盗難届の出ている飛行船が、管理本部へと接近中です。","ENG":"An airship reported stolen from Chamber is approaching the Administration Headquarters.","TWN":"一艘在強巴被通報失竊的飛行船，正在接近管理本部。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"ADMIN_OMEN_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_OMEN_OPR_NULL","text":{"KOREA":"본인이 힉스라고 주장하는군요.","JPN":"自らをヒックスだと主張しています。","ENG":"The pilot claims to be Hicks.","TWN":"對方自稱是希克斯。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"ADMIN_OMEN_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"예니카? 챔버를 지키고 있어야 할 녀석이 왜 이곳에...?","JPN":"イェニカ？　チェンバーを守っているはずのあいつが、どうしてここに……？","ENG":"Yanikka? Why is someone who should be guarding Chamber coming here...?","TWN":"耶妮卡？本該守在強巴的那傢伙怎麼會來這裡……？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"됐고, 타임머신 여기 있지?","JPN":"それはさておき、タイムマシン、ここにあるんでしょう？","ENG":"Enough of that. The time machine is here, right?","TWN":"算了。時光機在這裡吧？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"타임머신이라고?","JPN":"タイムマシンだと？","ENG":"Time machine?","TWN":"時光機？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"세상이 클리파로 뒤범벅일 때만 탈 수 있는 타임머신이 조금 있으면 출발한다며?","JPN":"世界がクリファでぐちゃぐちゃになっている時にだけ乗れるタイムマシンが、もうすぐ出発するんだってね？","ENG":"I heard there's a time machine that can only be used when the world is completely flooded with Qlipha, and it's about to depart.","TWN":"聽說有一台只有在世界被逆卡巴拉淹沒時才能啟動的時光機，很快就要出發了？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그런 얘긴 누구한테 들은 거지?","JPN":"そういう話は誰から聞くんだ？","ENG":"Who did you hear that from?","TWN":"你從哪裡聽來的？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"역시 있구나? 나도 그거 탈래! 폐는 절대 안 끼칠 테니까!","JPN":"やっぱりあるんだね？　私もそれ乗る！　絶対迷惑かけないから！","ENG":"So it does exist? I want to ride it too! I swear I won't cause any trouble!","TWN":"果然有吧？我也要搭！我絕對不會添麻煩！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하아.","JPN":"はあ。","ENG":"*Sigh*","TWN":"唉。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"시니어 잭슨이 없으면 통제불능이란 건 알고 있었지만, 활약상을 듣고 잠시나마 안심한 내가 어리석었군.","JPN":"シニア・ジャクソンがいないと統制不能だということは分かっていたが、活躍を聞いて一時でも安心した私がバカだった。","ENG":"I knew she'd be uncontrollable without Senior Jackson, but hearing about her recent achievements made me relax for a moment. That was foolish of me.","TWN":"雖然早就知道沒有Senior傑森的話她會失控，聽到她的戰績後一度放心的我，真是有夠愚蠢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"힉스, 격전지 무단 이탈 죄는 가볍지 않다는 걸 모르나?","JPN":"ヒックス、激戦地無断離脱罪は軽くないということを知らないのか。","ENG":"Hicks, do you not realize that abandoning a battlefield without authorization is a serious offense?","TWN":"希克斯，你知道擅自離開戰場罪名不輕吧？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"안 태워주면, 이대로 아무 건물이나 들이받는다!","JPN":"乗せてくれないと、このままビルに突進するよ！","ENG":"If you don't let me on, I'll just crash into any building I see!","TWN":"要是不讓我上去，我就直接撞向這裡的建築物！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"...이 멍청이가.","JPN":"……このバカが。","ENG":"...This idiot.","TWN":"……這個笨蛋。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"subtitle","speaker":null,"text":{"KOREA":"3시간 전, 챔버","JPN":"3時間前、チェンバー","ENG":"3 hours earlier, Chamber.","TWN":"3小時前，強巴","DEU":"3 hours earlier, Chamber.","FRA":"3 hours earlier, Chamber."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"휴- 잔뜩 놀아버렸다- 피가 끈적해.","JPN":"ふう～いっぱい遊んじゃった～血がベタベタ。","ENG":"Phew! That was a lot of fun. My blood's getting sticky.","TWN":"呼—玩得太過頭了—血都變得黏答答的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으슥한 곳에서 숙녀를 습격했으니, 너희 전부 찢어 갈겨버려도 정당방위네? 그렇지?","JPN":"薄暗いところで乙女を襲撃したんだから、あなたたち全員八つ裂きにしても正当防衛でしょう？　ね？","ENG":"You ambushed a lady in a dark alley, so tearing you all to shreds would count as self-defense, right?","TWN":"在這種暗巷裡襲擊淑女，就算我把你們全都撕碎，也算正當防衛吧？對吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CULTIST_NPC_NULL_MASK","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"},"C":{"char_id":"CULTIST_NPC_NULL_MASK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗, 기껏 죽였는데 시체가 일어나잖아?","JPN":"あっ、せっかく殺したのになんで死体が起き上がるわけ？","ENG":"Hey, I killed you already, and now the corpse is getting back up?","TWN":"啊？好不容易殺死的屍體又站起來了？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"기분 나빠-","JPN":"気持ち悪う～","ENG":"That's disgusting.","TWN":"真噁心—"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CULTIST_NPC_NULL_MASK","text":{"KOREA":"우리는, 너의 소중한 것을 원한다.","JPN":"我らは、お前の大切なものを望む。","ENG":"We desire something precious to you.","TWN":"我們，需要你珍貴的東西。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_MASK","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};